#!/bin/sh
# Auto-generated POSIX shell benchmark -- do not edit by hand.
# Generated by scripts/gen_bench.py

set -e

BENCH_DIR=$(mktemp -d)
trap 'rm -rf "$BENCH_DIR"' EXIT

section_time() {
    _label=$1; shift
    _start=$(date +%s)
    "$@"
    _end=$(date +%s)
    printf "  %-40s %ss\n" "$_label" "$(( _end - _start ))"
}

printf "=== meiksh benchmark ===\n"
BENCH_START=$(date +%s)

bench_arithmetic() {
  i=0
  while [ $i -lt 196300 ]; do
    a=$(( i * 137 + 42 ))
    b=$(( a % 97 ))
    _t1=$(( a << 2 ))
    _t2=$(( b >> 1 ))
    c=$(( _t1 + _t2 ))
    _t3=$(( a & 0xff ))
    d=$(( c ^ _t3 ))
    _t4=$(( b + 1 ))
    e=$(( d | _t4 ))
    f=$(( e > d ? e - d : d - e ))
    g=$(( a != 0 && b != 0 ))
    h=$(( f >= 0 || g <= 1 ))
    acc=$(( a + b + c + d + e + f + g + h ))
    _t5=$(( i + 1 ))
    j=$(( acc / _t5 ))
    k=$(( j * j - j + 17 ))
    _t6=$(( k % 251 ))
    _t7=$(( i & 0x3f ))
    m=$(( _t6 + _t7 ))
    n=$(( ~m + 1 ))
    p=$(( n < 0 ? 0 - n : n ))
    q=$(( p * 3 + i * 7 - 19 ))
    _t8=$(( q >> 3 ))
    r=$(( _t8 & 0xfff ))
    i=$(( i + 1 ))
  done
}

bench_expansion() {
  base='the-quick-brown-fox-jumps-over-the-lazy-dog/path/to/some/file.tar.gz'
  i=0
  while [ $i -lt 135600 ]; do
    a=${base:-fallback_value}
    b=${base%.*}
    c=${base%%.*}
    d=${base#*/}
    e=${base##*/}
    f=${#base}
    g=${base%.tar.gz}
    h=${base##*-}
    j=${base%/*}
    k=${base:-""}
    m=${base#the-}
    n=${base%%/*}
    p=${base%%-*}
    q=${base##*over-}
    r=${base#*fox}
    s=${base%dog*}
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h" "$j" "$k" "$m" "$n" "$p" "$q" "$r" "$s"
    i=$(( i + 1 ))
  done
}

fib_iter() {
  _n=$1; _a=0; _b=1; _j=0
  while [ $_j -lt $_n ]; do
    _t=$(( _a + _b )); _a=$_b; _b=$_t; _j=$(( _j + 1 ))
  done
  FIB_RESULT=$_a
}

accumulate() {
  _sum=0; _idx=0
  while [ $_idx -lt $1 ]; do
    _sum=$(( _sum + _idx * _idx ))
    _idx=$(( _idx + 1 ))
  done
  ACC_RESULT=$_sum
}

is_prime() {
  _num=$1
  if [ $_num -lt 2 ]; then PRIME_RESULT=0; return; fi
  _d=2
  _sq=$(( _d * _d ))
  while [ $_sq -le $_num ]; do
    if [ $(( _num % _d )) -eq 0 ]; then PRIME_RESULT=0; return; fi
    _d=$(( _d + 1 ))
    _sq=$(( _d * _d ))
  done
  PRIME_RESULT=1
}

bench_functions() {
  i=0
  while [ $i -lt 6400 ]; do
    fib_iter 30
    accumulate 20
    is_prime $(( i % 997 + 2 ))
    : "$FIB_RESULT" "$ACC_RESULT" "$PRIME_RESULT"
    i=$(( i + 1 ))
  done
}

bench_splitting() {
  data='alpha:bravo:charlie:delta:echo:foxtrot:golf:hotel:india:juliet'
  i=0
  while [ $i -lt 271400 ]; do
    old_ifs=$IFS
    IFS=:
    set -- $data
    count=$#
    IFS=$old_ifs
    set -- $data
    count2=$#
    long="aa bb cc dd ee ff gg hh ii jj kk ll mm nn oo pp"
    set -- $long
    count3=$#
    : "$count" "$count2" "$count3"
    i=$(( i + 1 ))
  done
}

bench_globbing() {
  gdir="$BENCH_DIR/globtest"
  mkdir -p "$gdir"
  j=0
  while [ $j -lt 500 ]; do
    : > "$gdir/file_${j}.txt"
    : > "$gdir/data_${j}.dat"
    : > "$gdir/log_${j}.log"
    j=$(( j + 1 ))
  done
  i=0
  while [ $i -lt 2800 ]; do
    set -- "$gdir"/*.txt
    c1=$#
    set -- "$gdir"/*.dat
    c2=$#
    set -- "$gdir"/*.log
    c3=$#
    set -- "$gdir"/file_1??.txt
    c4=$#
    set -- "$gdir"/*_[0-9].txt
    c5=$#
    : "$c1" "$c2" "$c3" "$c4" "$c5"
    i=$(( i + 1 ))
  done
  rm -rf "$gdir"
}

bench_subshells() {
  i=0
  while [ $i -lt 300 ]; do
    a=$(echo "sub_$i" | cat)
    b=$( ( echo inner_a; echo inner_b ) | cat -n )
    c=$(printf "%d %d %d" $i $((i+1)) $((i+2)))
    d=$(echo $i | { read x; echo $(( x * 2 )); })
    : "$a" "$b" "$c" "$d"
    i=$(( i + 1 ))
  done
}

bench_io() {
  iofile="$BENCH_DIR/iotest.txt"
  : > "$iofile"
  i=0
  while [ $i -lt 1000 ]; do
    echo "line_$i alpha bravo charlie delta echo foxtrot golf hotel" >> "$iofile"
    i=$(( i + 1 ))
  done
  count=0
  while IFS= read -r line; do
    count=$(( count + 1 ))
  done < "$iofile"

  outfile="$BENCH_DIR/ioout.txt"
  i=0
  while [ $i -lt 2500 ]; do
    cat >> "$outfile" <<HEREDOC_END
Line $i: The quick brown fox jumps over the lazy dog.
Expansion: var=${i} arith=$((i * 2 + 1))
More text with "quotes" and special chars: $count
HEREDOC_END
    i=$(( i + 1 ))
  done
  fdfile="$BENCH_DIR/fdtest.txt"
  i=0
  while [ $i -lt 2500 ]; do
    echo "fd_line_$i" 3>"$fdfile" >&3
    i=$(( i + 1 ))
  done
  : "$count"
}

bench_traps() {
  i=0
  while [ $i -lt 307000 ]; do
    trap ":" USR1
    trap ":" USR2
    trap ":" INT
    trap - USR1
    trap - USR2
    trap - INT
    i=$(( i + 1 ))
  done
}

